var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"아빠, 저거 봐! 코끼리다, 코끼리!","JPN":"パパ、あれ見て！　ゾウさんだよ、ゾウさん！","ENG":"Daddy, look! It’s an elephant!","TWN":"爸爸，你看！是大象欸！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WORKER_NPC_PANK_NULL","text":{"KOREA":"으음, 그렇구나. 우리에 갇혀 있는 코끼리구나.","JPN":"うーん、そうだね。檻に閉じ込められてるゾウさんだね。","ENG":"Right, right. It’s an elephant in a cage.","TWN":"嗯～是欸，是被人類關起來的大象。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WORKER_NPC_PANK_NULL","text":{"KOREA":"먹고 자고 편하게 쉬고 평화로워 보이지만, 결국 저 친구도 울타리에 갇힌 채 벗어나지 못하는 거겠지.","JPN":"食べて寝て休んで平和そうに見えるけど、結局あの子も檻に閉じ込められたまま出られないんだ。","ENG":"Eating, sleeping, and resting, it looks so peaceful. But that friend eventually won’t be able to escape its cage.","TWN":"你看牠有得吃有得睡，一副很安逸的樣子，其實是被關在柵欄裡逃不出去。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WORKER_NPC_PANK_NULL","text":{"KOREA":"동물원에서 태어난 저 코끼리는 사바나 초원의 자유를 알고 있을까?","JPN":"動物園で生まれたあのゾウは、サバナ草原での自由を知ってるのかな？","ENG":"Elephants born in the zoo will never know the freedom of Savannah.","TWN":"在動物園裡出生的大象，會知道草原的自由嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WORKER_NPC_PANK_NULL","text":{"KOREA":"모르겠지. 분명 모를 거야.","JPN":"知らないだろうな。きっと知らない。","ENG":"They’ll never know. Never.","TWN":"當然不知道囉，怎麼可能知道呢。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"서커스 직원 아저씨, 저희 아빠가 이상해요.","JPN":"サーカスのおじさん、パパがおかしいよ。","ENG":"Mr. Circus clown, Daddy’s acting weird.","TWN":"馬戲團叔叔，我爸爸好奇怪。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"흔한 증상이니 괜찮습니다. 사회인들의 비애라는 거죠.","JPN":"よくある症状ですので、大丈夫ですよ。社会人のもの悲しさというものです。","ENG":"It’s a common symptom. It’s called grief of members of society.","TWN":"沒事的，這是正常的反應，可以說是職場人士的悲哀。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"흠… 저도 어른이 되면 아빠처럼 되는 건가요?","JPN":"ふーん……ボクも大人になったらパパみたいになるの？","ENG":"Hmm... Will I be like Daddy if I grow up?","TWN":"嗚…等我長大後也會跟爸爸一樣嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 글쎄요.","JPN":"フフ、どうでしょう。","ENG":"Ha ha, we’ll have to see about that.","TWN":"呵呵，那我就不知道囉～"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"분명한 건 지금은 그런 걱정이 필요 없다는 거죠.","JPN":"確かなのは、今はそんなことを心配する必要がないということです。","ENG":"One thing for sure is that you don’t have to worry about stuff like that now.","TWN":"我只知道，現在的你還不需要擔心這種事。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"먼 미래를 걱정하는 건, 그날의 당신이 가질 몫이니까요.","JPN":"遠い未来を心配するのは、未来のあなたの務めですから。","ENG":"It’s up to the future you to worry about the distant future.","TWN":"未來的事，就交給未來的你去擔心吧。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"오늘은 그저 코끼리와 악어를 구경하면서 즐겁게 시간을 보내는 겁니다.","JPN":"今日はただ、ゾウさんとワニさんを見ながら楽しく過ごすのです。","ENG":"You shall just enjoy today, looking at the crocodiles and elephants.","TWN":"今天的你，只需要好好欣賞大象和鱷魚，度過開心的一天。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"…그렇구나.","JPN":"……そっか。","ENG":"...Okay.","TWN":"…是喔。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"그치만 저 코끼리 귀만 펄럭거리고 안 움직이는 걸. 시시해.","JPN":"でもあのゾウさん、耳をパタパタしてるだけで動かないよ。つまんない。","ENG":"But that elephant isn’t moving. It’s only flapping its ears. Boring.","TWN":"可是那個大象只有耳朵在動，好無聊喔。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 아무래도 예정에 없던 퍼레이드가 시작될 모양이군요.","JPN":"フフ、どうやら予定にはなかったパレードが始まりそうですね。","ENG":"Ha ha, it looks like an unexpected parade is about to begin.","TWN":"呵呵，行程之外的遊行好像要開始囉。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"퍼레이드?","JPN":"パレード？","ENG":"A parade?","TWN":"遊行？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그렇습니다.","JPN":"そうです。","ENG":"That's correct.","TWN":"對喔。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그러니 당신들은 저기에 있는 전망대로 올라가세요.","JPN":"ですから、あなたたちはあそこにある展望台に上がってください。","ENG":"You two go up to the observatory over there.","TWN":"你們快上去那個瞭望台，"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"퍼레이드를 감상하기엔 안성맞춤인 곳이니까요.","JPN":"パレードを観賞するにはうってつけの場所ですから。","ENG":"It will be the perfect place to watch the parade.","TWN":"那邊的視野看遊行得最清楚。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"응, 알겠어!","JPN":"うん、わかった！","ENG":"Okay!","TWN":"嗯，好！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"아빠! 나 저기 올라가고 싶어! 퍼레이드 구경할래!","JPN":"パパ！　ボク、あっちに行きたい！　パレード見る！","ENG":"Daddy! I want to go up there! I want to watch the parade!","TWN":"爸爸！我想上去那裡！我要看遊行！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WORKER_NPC_PANK_NULL","text":{"KOREA":"응…? 퍼레이드? 이 유원지에 그런 일정도 있었던가?","JPN":"うん……？　パレード？　この遊園地にそんなものあったっけ？","ENG":"Huh...? Parade? They also have parades at the amusement park?","TWN":"嗯…？遊行？這個遊樂園還有遊行喔？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"확실히 촬영을 방해하기엔 안성맞춤인 계획이군요.","JPN":"確かに撮影の邪魔をするにはうってつけの計画ですね。","ENG":"Well, looks like the perfect plan to bother a shoot.","TWN":"這個計畫確實是很適合妨礙拍攝。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 그 상대가 제 동생만 아니었다면 효과를 볼 수 있었을 텐데 말이죠.","JPN":"フフ、その相手が私の妹でさえなければ、効果があったはずでしたがね。","ENG":"Ha ha, the plan would have been effective if only the opponent wasn’t my sister.","TWN":"呵呵，但很可惜對方是我妹妹，否則效果應該會很不錯。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"로미오. 내가 말했지?","JPN":"ロミオ。言っただろう？","ENG":"Romeo. I told you.","TWN":"羅密歐，我說過，"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"난 가지기로 한 건 무조건 가진다고.","JPN":"アタシはほしいものは絶対手に入れるって。","ENG":"Once I want it, I have to get it.","TWN":"只要是我想要的東西，就一定要得到手！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"그런 식으로 협박한다고 해서 진짜 사랑을 얻을 수 있을 것 같아?","JPN":"そんなふうに脅して、本物の愛を手に入れられると思うのか？","ENG":"You think you’ll be able to win my love by threatening me like that?","TWN":"你以為這樣威脅我，就可以得到你想要的愛情嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"당신이란 여자는 정말 최악…!","JPN":"君という女は本当に最悪……！","ENG":"You’re the worst...!","TWN":"像你這種女人真的是非常糟…！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"…응?","JPN":"……ん？","ENG":"...Huh?","TWN":"…嗯？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"뭐야? 왜 사람들이 이쪽으로 달려오는 거지?","JPN":"なんだ？　どうして人々がこっちに走ってきてるんだ？","ENG":"What is it? Why are people all running this way?","TWN":"怎麼搞的？人怎麼都往這衝過來？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_NULL","text":{"KOREA":"감독님! 유원지에 있던 동물들이 갑자기 전부 탈출했습니다!","JPN":"監督！　遊園地にいた全ての動物たちがいきなり脱走しました！","ENG":"Mr. Director! All the animals in the amusement park suddenly escaped!","TWN":"導演！遊樂園裡的動物全都逃出來了！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_NULL","text":{"KOREA":"촬영을 멈추고 피하셔야 해요!","JPN":"撮影を中止して逃げてください！","ENG":"We have to stop the shoot and get away!","TWN":"先暫停拍攝趕快逃吧！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"아니. 끊지 마. 촬영은 계속 진행한다.","JPN":"いや。止めるな。撮影を続ける。","ENG":"No. We don’t stop. We go on with the shoot.","TWN":"不，不許停，繼續拍。"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_NULL","text":{"KOREA":"네?! 그, 그게 대체 무슨 말씀…","JPN":"ええっ！？　そ、それはなんで……","ENG":"W-what do you mean?","TWN":"什麼？！導演你在說什…"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_NULL","text":{"KOREA":"흐익! 왔다!","JPN":"ひいっ！　来た！","ENG":"Yikes! It’s here!","TWN":"哇啊！衝過來啦！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"동물들이 이쪽으로 온다! 도망쳐!","JPN":"動物たちがこっちに来る！　逃げろ！","ENG":"The animals are all coming this way! Make a run for it!","TWN":"動物衝過來啦！快逃！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM"},{"id":"L11_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"아빠! 저거봐! 사자들이 달리고 있어!","JPN":"パパ！　あれ見て！　ライオンさんたちが走ってる！","ENG":"Daddy, look! The lions are all running!","TWN":"爸爸你看！獅子在奔跑欸！"},"stage":{"bg":"CORRIDOR_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WORKER_NPC_PANK_NULL","text":{"KOREA":"…세상에. 저 밑에서 대체 무슨 일이 일어나고 있는 거야?","JPN":"……そんな。下でいったい何が起きてるんだ？","ENG":"...Oh dear. What's happening down there?","TWN":"…天啊，下面到底發生什麼事？"},"stage":{"bg":"CORRIDOR_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"여기는 비둘기. 마다가스카는 이로서 자유를 되찾았다. 오버.","JPN":"こちらハト。マダガスカルはこれにて自由を取り戻した、以上。","ENG":"This is Pigeon. Madagascar is now free. Over.","TWN":"這裡是鴿子，馬達加斯加已經重獲自由，Over！"},"stage":{"bg":"CORRIDOR_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"몇 마리가 유원지 밖으로 벗어나긴 했는데… 어쩔까?","JPN":"何匹か遊園地の外に飛び出したんだが……どうする？","ENG":"Some of the animals escaped the amusement park... What should we do with them?","TWN":"不過有幾隻跑到園外…怎麼辦？"},"stage":{"bg":"CORRIDOR_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"수고했어. 그런 건 경찰들이 알아서 잘 처리하겠지.","JPN":"お疲れ様。そんなものは警察でなんとかするわよ。","ENG":"You did well. The cops will take care of the animals.","TWN":"辛苦了，那種事就交給警察處理吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"후훗, 좋아. 이걸로 촬영은 완전히 끝이야.","JPN":"フフッ、よし。これで撮影は完全に終わりね。","ENG":"Ha ha, great. The shoot will be completely doomed.","TWN":"呵呵，非常好，這樣肯定是拍不下去了。"},"stage":{"bg":"CORRIDOR_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"이렇게 되면 예고편에는 내 촬영분을 사용할 수밖에 없겠지.","JPN":"こうなったら予告編には私の撮影シーンを使うしかないわよ。","ENG":"If things go as planned, they’ll have no choice but to use my film for the trailer.","TWN":"看來預告就只能用我拍的影片囉！"},"stage":{"bg":"CORRIDOR_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"니콜라스 씨에겐 유감이지만, 여기서 살짝 다쳐준다면 재촬영도 불가능할 테고.","JPN":"ニコラスさんには残念だけど、ここでちょっとだけ怪我してくれれば撮り直しもできないはずだし。","ENG":"I feel a bit sorry for Mr. Nicholas, but if he gets hurt, he won’t be able to film again.","TWN":"雖然對尼可拉斯有點不好意思，畢竟他只要稍微受點傷就無法再重拍。"},"stage":{"bg":"CORRIDOR_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"엇, 저게 뭐지? 유원지 쪽에서 엄청난 게......","JPN":"ちょっ、ありゃ何なんだ？　遊園地の方からとんでもないものが……","ENG":"Huh? What's that? There's something huge coming from the park...","TWN":"咦，那是什麼？遊樂園那邊好像有什麼……"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"으아악- 코, 코끼리다!","JPN":"うわあーっ、ゾ、ゾウだ！","ENG":"Eeek! It's an elephant!","TWN":"哇啊啊- 是…是大象！"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM"},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"꺄악! 저기 사람이 위험해요!","JPN":"きゃあっ！　あの人、危ないわ！","ENG":"Eeek! There’s someone in danger!","TWN":"呀啊！那邊的人有危險！"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"엄마랑 아이가 넘어졌어! 저대로 뒀다간 큰일이......!","JPN":"母親と子供が転んでしまったぞ！　あのまま放っておくと大変なことに……！","ENG":"The mom and her kid fell over! They'll be trampled if nobody helps them!","TWN":"媽媽和小孩摔倒了！這樣下去會出事的……！"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"자! 일어날 수 있겠어요?","JPN":"ほら！　立てそうですか？","ENG":"Hey! You think you can get up?","TWN":"來！能站起來嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MOTHER_EXTRA_NULL_NULL","text":{"KOREA":"으으...... 그게, 다리가 접질려서......","JPN":"うぅ……その、足をくじいてしまいまして……","ENG":"Hngh... I think I sprained my ankle...","TWN":"嗚嗚……我的腳扭到了……"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"그럼 제가 업어볼게요!","JPN":"じゃあ、アタシがおんぶします！","ENG":"Let me try to carry you!","TWN":"我來揹你！"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BEAR_EXTRA_NULL_NULL","text":{"KOREA":"쿠워어어어어!!!","JPN":"ガオオオオオ！！","ENG":"Rooooaar!","TWN":"吼吼吼吼吼！！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HOWLING_02"},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"곰이다! 잡아먹히겠어!","JPN":"クマだ！　食べられる！","ENG":"It’s a bear! We’re going to get eaten up!","TWN":"有熊！牠會吃掉我們！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"유원지에서 곰이 풀려났어! 모두 도망쳐!","JPN":"遊園地からクマが脱走した！　みんな逃げろ！","ENG":"The bear got out from the amusement park! Everyone, run!","TWN":"有熊從遊樂園逃出來啦！大家快逃！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗! 저기 있어! 레빗 센스, 오늘도 또 한 건 해결!","JPN":"あっ！　あっちにいる！　ラビットセンス、今日も一件落着！","ENG":"Oh! There it is! Rabbit Sense saves the day again!","TWN":"喔！在那裡！兔兔感應！今天又解決一件囉！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"이번엔 도움이 필요한 곰을 찾다니! 역시 하림 대장이다!","JPN":"今度は助けが必要なクマを見つけるとは！　流石はウサギ隊長だ！","ENG":"This time, finding a bear in need! Captain Harim to the rescue!","TWN":"這次也順利找到需要幫助的熊！真不愧是夏琳隊長！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"혹시 저 곰이 뭐라고 말하고 있는지도 알 수 있는 건가?","JPN":"もしかしてあのクマが何を言っているのかもわかるか？","ENG":"Do you also know what the bear is trying to say?","TWN":"敢問隊長，你也可以知道那隻熊現在在說什麼嗎？"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"으음…","JPN":"うーん……","ENG":"Hmm...","TWN":"嗯…"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"BEAR_EXTRA_NULL_NULL","text":{"KOREA":"쿠워어어어!!","JPN":"ガオオオオ！","ENG":"Rooooaar!","TWN":"吼吼吼吼吼！！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_HOWLING_02"},{"id":"L1_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"우오오!! 배고픈데 집에 돌아가는 길을 잊어버렸어!","JPN":"うわあ！！　腹減ってるのに家までの帰り道を忘れちゃった！","ENG":"Roar!! I’m hungry but I don’t remember the way back home!","TWN":"喔喔喔！牠說牠肚子餓，但是找不到回家的路！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"…라는데?","JPN":"……だって。","ENG":"...That’s what it says.","TWN":"…好像是這樣？"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"힉!","JPN":"ひいっ！","ENG":"Eeek!","TWN":"唔！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"어이, 로미오. 어딜 가?","JPN":"おい、ロミオ。どこへ行く？","ENG":"Hey, Romeo. Where are you going?","TWN":"喂，羅密歐，你要去哪？"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"파, 파벨라? 우리 도망쳐야 할 것 같은데?","JPN":"ふぁ、ファヴェーラ？　俺たち、逃げないといけないみたいだが？","ENG":"F-Fabella? I think we should run away.","TWN":"帕…帕貝拉？我們現在應該要趕快逃命吧？"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"앙? 도망? 뭐하러?","JPN":"ああん？　逃げる？　なんで？","ENG":"Huh? Run away? What for?","TWN":"蛤？逃什麼命？幹嘛逃？"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"그러니까… 저런 사자 같은 건 사람을 잡아먹을 수도 있다고. 그 정돈 알잖아? 그렇지?","JPN":"だから……ああいうライオンは人を食べることもあるんだ。それくらいは知ってるだろう？　なっ？","ENG":"Because... Those lions, they eat people! You know that, right?","TWN":"你沒看到嗎… 獅子是會吃人的欸！這點常識你應該有吧？"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"아직 내 질문에 대한 대답을 못 들었거든?","JPN":"まだ私の質問への答えを聞いてないんだが？","ENG":"I haven’t got a reply for my question yet.","TWN":"可是我還沒聽到你的回答？"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"선택해. 날 사랑할 건지, 아니면... 프레데리카를…","JPN":"選べ。私のことを愛するか、それとも……フレデリカを……","ENG":"Decide. Whether to love me, or... Frederica...","TWN":"你說，你選我，還是…選弗蕾德莉卡…"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"여기! 이쪽으로 숨어!","JPN":"こっちだ！　こっちに隠れろ！","ENG":"Here! Hide over here!","TWN":"這裡！躲到這裡來！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"이봐! 마취총 준비해!","JPN":"おい！　麻酔銃を持ってこい！","ENG":"Hey! Get the tranq gun ready!","TWN":"喂！快準備麻醉槍！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"…프레데리카를… 뭐였지?","JPN":"……フレデリカを……なんだっけ？","ENG":"...Frederica... What was it?","TWN":"…弗蕾德莉卡…什麼？"},"stage":{"bg":"BLACK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"사자 무리가 촬영장 쪽으로 간다! 위험해!","JPN":"ライオンの群れが撮影所に向かっている！　危ない！","ENG":"The lions are headed to the set! Watch out!","TWN":"獅子們往拍攝現場的方向衝過去啦！危險！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"이러다간 인명피해가 생기겠어! 실탄이라도 쏴 버려!","JPN":"このままだと死傷者が出る！　実弾でも撃ってしまえ！","ENG":"Someone’s going to get hurt! Somebody, shoot them!","TWN":"這樣下去恐怕會造成人員傷亡！實彈射殺！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"으아아, 이젠 도망치긴 늦었어… 사자밥이 되고 말 거라고…!","JPN":"うわあ、もう手遅れだ……ライオンのエサになってしまう……！","ENG":"Ahh, it’s too late to run away... We’ll all end up as prey...!","TWN":"嗚嗚嗚，現在也來不及逃了…我要成為獅子的晚餐了…！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"야, 큰 고양이.","JPN":"おい、デカい猫。","ENG":"Hey, big cat.","TWN":"喂，大貓咪！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"시끄러워서 대사 까먹었잖아.","JPN":"騒がしくてセリフを忘れたじゃないか。","ENG":"I forgot my lines because of all the noise.","TWN":"你好吵，害我都忘記台詞了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L36_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"꺼져.","JPN":"失せろ。","ENG":"Now get out.","TWN":"走開！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L39_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"사자들이… 왜 갑자기 얌전해진 거지?","JPN":"なんで……ライオンたちがいきなり大人しくなったんだ？","ENG":"The lions... Why did they become calm all of a sudden?","TWN":"獅子…好像突然都安靜下來咧？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHILD_NPC_PARK_NULL","text":{"KOREA":"아빠 보여? 동물들이 동시에 멈췄어!","JPN":"パパ、見える？　動物さんたち、みーんな止まっちゃった！","ENG":"Daddy, look! The animals all stopped!","TWN":"爸爸你有看到嗎？動物都停下來咧！"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"WORKER_NPC_PANK_NULL","text":{"KOREA":"그래… 게다가 저 동물들 지금… 자기 집으로 가는 거지?","JPN":"そうだな……しかもあの動物たち、今……自分のお家に帰ろうとしてるな？","ENG":"Right... And the animals... they’re all going back to their cages?","TWN":"嗯嗯…而且那些動物…現在都乖乖回家咧？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"뭐야? 뭔 일이 일어나고 있는 거야?","JPN":"何？　いったい何が起きてるの？","ENG":"What? What’s happening?","TWN":"搞什麼？現在是怎麼回事？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"왜 동물들이 난동을 피우다 말고 우리로 돌아가는 건데?","JPN":"どうして動物たちが暴れるのをやめて、檻に戻ってるのよ！","ENG":"Why are the animals all returning to their cages?","TWN":"動物怎麼都乖乖地回籠子裡去？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"이봐! 이게 대체 어떻게 된 거지?","JPN":"ちょっと！　これ、どういうこと？","ENG":"Hey! What’s going on?","TWN":"喂！這到底是怎麼回事？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"그야 모르지. 우린 그냥 시킨 대로 동물을 풀어줬을 뿐이라고.","JPN":"知らないな。俺たちはただ言われたとおりに動物たちを解放してやっただけだ。","ENG":"We don’t know. We just let out the animals like you told us to.","TWN":"我怎麼知道？我們就照你的吩咐，把動物放出來而已！"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L2_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"크윽…!","JPN":"くうっ……！","ENG":"Errgh...!","TWN":"可惡…！"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"안 되겠어. 그냥 저 여잘 쏴 버려!","JPN":"このままじゃダメ。あの女を撃ちなさい！","ENG":"I can’t stand it any more. Just shoot the girl!","TWN":"不行！給我開槍射那個女的！"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"음? 경쟁 차원에서 리타이어만 시켜달라더니. 그건 좀 과잉대응 아닌가?","JPN":"む？　オーディションの邪魔を頼むって言ったじゃないか。それはちょっとやりすぎだ。","ENG":"Hmm? You just wanted the girl to retire. Isn’t that too much?","TWN":"什麼？你當初只說要讓那個女的無法和你競爭，現在這樣是不是有點超過？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"뭐래? 누가 봐도 카운터잖아! 당신들이 제압탄을 쏟아부어봐야 기절하는 정도일 거라고!","JPN":"何言ってるの。どう見てもカウンターじゃない！　あなたたちが制圧弾を撃ちまくったって、気絶するくらいでしょ！","ENG":"What? Look, she’s definitely a Counter! Even though you rain bullets on her, she’ll only pass out!","TWN":"你說什麼？她很明顯是制裁者吧！吃幾顆子彈頂多暈過去而已！"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"돈을 받았으면 돈 값을 해!","JPN":"お金をあげたんだから、それくらいしなさいよ！","ENG":"I paid you well. I want your work to be worth the money!","TWN":"拿錢就應該要辦事吧！"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"칫, 모처럼 집중 좀 해보려 했더니 왠 하룻고양이 때문에 다 망쳤잖아.","JPN":"チッ。せっかく集中しようと思ったのに、子猫のせいで無駄になっちまった。","ENG":"Tch! All I wanted to do was concentrate but some cat ruined it all.","TWN":"嘖，我好不容易才能專心一點，結果大貓咪跑出來礙事！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"…사, 살았다.","JPN":"……た、助かった。","ENG":"...I-I’m alive.","TWN":"…呼，得救了。"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"어이, 괜찮아? 로미오?","JPN":"おい、大丈夫か？　ロミオ。","ENG":"Hey, you all right? Romeo?","TWN":"喂，你沒事吧？羅密歐？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"아, 덕분에요.","JPN":"お、おかげさまで。","ENG":"Yeah, thanks to you.","TWN":"嗯，謝謝你。"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"당신이 방금 동물들을 쫓아낸 건가요? 도대체 어떻게 한 거죠?","JPN":"あなたがさっき動物たちを追い払ったんですか？　いったいどうやって？","ENG":"Did you shoo away the animals? How did you do that?","TWN":"剛才是你把動物趕走的嗎？你是怎麼辦到的？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"엉? 더 약한 것들이 꼬리 내리는 건 당연한 거지. 뭐 그런 걸 물어?","JPN":"ああ？　弱いやつらが尻尾を巻いただけだ。そんなこと聞くな。","ENG":"Huh? It’s normal for the weak to lower their tails. You call that a question?","TWN":"嗯？弱者聽強者的話不是很正常嗎？你不知道喔？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"하하…","JPN":"ハハ……","ENG":"Haha...","TWN":"哈哈…"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"…아하하하하!!","JPN":"……アハハハハ！！","ENG":"...Ah hah hah hah hah!","TWN":"…哈哈哈哈！！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 왜 손을 잡고 그래? 방금 전까지 싫다고 빼더니…","JPN":"な、なんだよ？　なんでいきなり手を握るんだ？　さっきまで嫌だって言ってたくせに……","ENG":"What is it? Why are you holding my hand? You said you didn’t like it a moment ago...","TWN":"你…你幹嘛？幹嘛牽我的手？剛剛不是還一副嫌棄的樣子嗎…"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"파벨라! 당신은 정말 멋져!","JPN":"ファヴェーラ！　君は本当に素敵だ！","ENG":"Fabella! You’re awesome!","TWN":"帕貝拉！你真的好帥！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"난 어쩌면 당신 같은 여자를 기다려왔을 지도 몰라.","JPN":"もしかしたら俺は、君のような女を待っていたのかもしれない。","ENG":"Maybe you’re the one I’ve been waiting for.","TWN":"你或許就是我在等的人！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"엥? 너 프레데리카는 어쩌고?","JPN":"はぁ？　あんた、フレデリカは？","ENG":"Huh? What about Frederica?","TWN":"蛤？那那個弗蕾德莉卡怎麼辦？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"물론 그녀도 나에겐 소중한 사람이지.","JPN":"もちろん、彼女も俺にとって大切な人だ。","ENG":"Of course Frederica is an important person to me.","TWN":"她對我當然也很重要，"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"하지만 지금만큼은 당신이 요구하는 대로 따르기로 했어.","JPN":"でも、今だけは君が望むままに従うことにしたよ。","ENG":"But for now, I decided to follow as you say.","TWN":"但現在，不管你說什麼我都聽你的。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"원래 사랑이라는 열차에 종착역이라는 건 없는 법이니까.","JPN":"そもそも愛という列車に終着点はないからな。","ENG":"Because there is no final destination for a train called love.","TWN":"愛情列車本來就沒有所謂的終點。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"왜 그래? 벌써부터 우리가 함께 이뤄 나갈 앞으로의 나날을 고민 중이야?","JPN":"どうした？　もう俺たちが一緒に築き上げるこれからの日々について考えているのか？","ENG":"What is it? Are you already wondering about the happy days we’ll spend together?","TWN":"你在想什麼？在想我們的將來嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"…숙여.","JPN":"……伏せろ。","ENG":"...Duck.","TWN":"…低頭。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"으헉?!","JPN":"うわっ！？","ENG":"Yikes?!","TWN":"呃呃？！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L40_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"이런. 탄환을 피했나?","JPN":"あーあ。弾丸をよけやがったか。","ENG":"Huh. Did she dodge the bullet?","TWN":"可惡，被她給閃過去了嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"확실히 카운터는 맞는 것 같구만.","JPN":"確かにカウンターみたいだな。","ENG":"She definitely seems like a Counter.","TWN":"看來她真的是制裁者。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","text":{"KOREA":"그럼 이쪽도 애써 힘 조절할 필요가 없지.","JPN":"じゃあ、こっちも力加減する必要はない。","ENG":"Then we don’t need to go easy on her.","TWN":"那我們也不需要手下留情囉！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARIES_NPC_SUPPLEMENT_FALLEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"파벨라? 방금 그건 뭐였지? 총소리? 제압해야 할 동물들은 이미 돌아갔을 텐데?","JPN":"ファヴェーラ？　今のはなんだったんだ？　銃声？　動物たちはすでに戻ったはずだろう？","ENG":"Fabella? What was that sound? Gunshots? I thought the animals already returned to their cages?","TWN":"帕貝拉？剛剛是怎麼回事？怎麼會有槍聲？動物不是都回家了嗎？"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"잔말 말고 여기 계속 처박혀 있어.","JPN":"つべこべ言わないで、ここに籠ってろ。","ENG":"Just be quiet and stay here.","TWN":"問那麼多幹嘛，你待在這裡！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"저것들은 내가 처리하고 올 테니까.","JPN":"あいつらはアタシがやっつけてくる。","ENG":"I’ll go deal with them.","TWN":"等我回來，我去把那些傢伙處理掉！"},"stage":{"bg":"PARK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};